import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  username: string;
  email: string;
}

export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: string;
  userId: string;
  amount: number;
  category: string;
  date: string; // ISO string
  description: string;
  type: TransactionType;
}

export interface Summary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
}

export interface AuthResponse {
  user: User;
  token: string;
}

// Navigation types
export type Page = 'dashboard' | 'reports' | 'transactions' | 'settings';

import { User, Transaction, AuthResponse } from '../types';

const USERS_KEY = 'smartspend_users';
const TRANSACTIONS_KEY = 'smartspend_transactions';
const SESSION_KEY = 'smartspend_session';

// Helper to simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const StorageService = {
  // --- Auth Methods ---

  async register(username: string, email: string, password: string): Promise<AuthResponse> {
    await delay(500);
    const usersStr = localStorage.getItem(USERS_KEY);
    const users: any[] = usersStr ? JSON.parse(usersStr) : [];

    if (users.find((u: any) => u.email === email)) {
      throw new Error('User already exists');
    }

    const newUser = {
      id: crypto.randomUUID(),
      username,
      email,
      password, // In a real app, hash this!
    };

    users.push(newUser);
    localStorage.setItem(USERS_KEY, JSON.stringify(users));

    const user: User = { id: newUser.id, username: newUser.username, email: newUser.email };
    const token = `mock-jwt-${newUser.id}`;

    localStorage.setItem(SESSION_KEY, JSON.stringify({ user, token }));
    return { user, token };
  },

  async login(email: string, password: string): Promise<AuthResponse> {
    await delay(500);
    const usersStr = localStorage.getItem(USERS_KEY);
    const users: any[] = usersStr ? JSON.parse(usersStr) : [];

    const foundUser = users.find((u: any) => u.email === email && u.password === password);

    if (!foundUser) {
      throw new Error('Invalid credentials');
    }

    const user: User = { id: foundUser.id, username: foundUser.username, email: foundUser.email };
    const token = `mock-jwt-${foundUser.id}`;

    localStorage.setItem(SESSION_KEY, JSON.stringify({ user, token }));
    return { user, token };
  },

  async logout(): Promise<void> {
    await delay(200);
    localStorage.removeItem(SESSION_KEY);
  },

  getSession(): { user: User, token: string } | null {
    const sessionStr = localStorage.getItem(SESSION_KEY);
    return sessionStr ? JSON.parse(sessionStr) : null;
  },

  // --- Transaction Methods ---

  async getTransactions(userId: string): Promise<Transaction[]> {
    await delay(300);
    const allTransactionsStr = localStorage.getItem(TRANSACTIONS_KEY);
    const allTransactions: Transaction[] = allTransactionsStr ? JSON.parse(allTransactionsStr) : [];
    return allTransactions.filter(t => t.userId === userId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  },

  async addTransaction(transaction: Omit<Transaction, 'id'>): Promise<Transaction> {
    await delay(300);
    const allTransactionsStr = localStorage.getItem(TRANSACTIONS_KEY);
    const allTransactions: Transaction[] = allTransactionsStr ? JSON.parse(allTransactionsStr) : [];

    const newTransaction: Transaction = {
      ...transaction,
      id: crypto.randomUUID(),
    };

    allTransactions.push(newTransaction);
    localStorage.setItem(TRANSACTIONS_KEY, JSON.stringify(allTransactions));
    return newTransaction;
  },

  async updateTransaction(updatedTransaction: Transaction): Promise<Transaction> {
    await delay(300);
    const allTransactionsStr = localStorage.getItem(TRANSACTIONS_KEY);
    let allTransactions: Transaction[] = allTransactionsStr ? JSON.parse(allTransactionsStr) : [];

    allTransactions = allTransactions.map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
    localStorage.setItem(TRANSACTIONS_KEY, JSON.stringify(allTransactions));
    return updatedTransaction;
  },

  async deleteTransaction(id: string): Promise<void> {
    await delay(300);
    const allTransactionsStr = localStorage.getItem(TRANSACTIONS_KEY);
    let allTransactions: Transaction[] = allTransactionsStr ? JSON.parse(allTransactionsStr) : [];

    allTransactions = allTransactions.filter(t => t.id !== id);
    localStorage.setItem(TRANSACTIONS_KEY, JSON.stringify(allTransactions));
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from "../types";

// Ensure API Key is available
const apiKey = process.env.API_KEY || '';
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const GeminiService = {
  isAvailable: !!ai,

  async categorizeTransaction(description: string): Promise<{ category: string; type: 'income' | 'expense' }> {
    if (!ai) return { category: 'Other', type: 'expense' };

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Categorize this transaction description: "${description}". 
        Return JSON with "category" (one of: Food & Drink, Housing, Transportation, Entertainment, Shopping, Health, Salary, Investment, Utilities, Other) and "type" (income or expense).`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              category: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['income', 'expense'] }
            }
          }
        }
      });

      const text = response.text;
      if (text) {
        return JSON.parse(text);
      }
      return { category: 'Other', type: 'expense' };
    } catch (error) {
      console.error("Gemini categorization failed:", error);
      return { category: 'Other', type: 'expense' };
    }
  },

  async analyzeSpending(transactions: Transaction[]): Promise<string> {
    if (!ai) return "AI services are not configured.";
    if (transactions.length === 0) return "No transactions to analyze.";

    const simplified = transactions.slice(0, 50).map(t => `${t.date}: ${t.description} (${t.type}) - $${t.amount} [${t.category}]`).join('\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze these financial transactions and provide a brief, helpful summary of spending habits and 2 actionable tips to save money. Keep it under 150 words.\n\n${simplified}`,
      });
      return response.text || "Could not generate insights.";
    } catch (error) {
      console.error("Gemini analysis failed:", error);
      return "Error generating insights. Please try again later.";
    }
  },

  async parseNaturalLanguage(input: string): Promise<Partial<Transaction> | null> {
    if (!ai) return null;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Parse this financial text into a transaction object: "${input}".
        Return JSON with fields: amount (number), description (string), category (string), type (income/expense), date (ISO string YYYY-MM-DD). Use today's date if not specified.`,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                amount: { type: Type.NUMBER },
                description: { type: Type.STRING },
                category: { type: Type.STRING },
                type: { type: Type.STRING, enum: ['income', 'expense'] },
                date: { type: Type.STRING }
              }
            }
        }
      });

      const text = response.text;
      return text ? JSON.parse(text) : null;
    } catch (error) {
      console.error("Gemini parsing failed:", error);
      return null;
    }
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 border text-sm font-medium rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 transition-colors duration-200";

  const variants = {
    primary: "border-transparent text-white bg-indigo-600 hover:bg-indigo-700 focus:ring-indigo-500",
    secondary: "border-gray-300 text-gray-700 bg-white hover:bg-gray-50 focus:ring-indigo-500",
    danger: "border-transparent text-white bg-red-600 hover:bg-red-700 focus:ring-red-500",
    ghost: "border-transparent text-indigo-600 bg-transparent hover:bg-indigo-50 focus:ring-indigo-500 shadow-none"
  };

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${className} ${disabled || isLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

export default Button;

import React from 'react';

