import React, { useState, useEffect } from 'react';
import { User, Transaction, Page } from './types';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import Auth from './components/Auth';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import TransactionForm from './components/TransactionForm';
import AIInsights from './components/AIInsights';
import Button from './components/Button';
import { Plus, Mic } from 'lucide-react';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [currentPage, setCurrentPage] = useState<Page>('dashboard');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | undefined>(undefined);
  const [isLoading, setIsLoading] = useState(true);

  // Load session and data
  useEffect(() => {
    const session = StorageService.getSession();
    if (session) {
      setUser(session.user);
      loadTransactions(session.user.id);
    }
    setIsLoading(false);
  }, []);

  const loadTransactions = async (userId: string) => {
    const data = await StorageService.getTransactions(userId);
    setTransactions(data);
  };

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    loadTransactions(loggedInUser.id);
  };

  const handleLogout = async () => {
    await StorageService.logout();
    setUser(null);
    setTransactions([]);
    setCurrentPage('dashboard');
  };

  const handleAddTransaction = async (data: Omit<Transaction, 'id'>) => {
    await StorageService.addTransaction(data);
    if (user) await loadTransactions(user.id);
    setShowAddModal(false);
  };

  const handleEditTransaction = async (data: Omit<Transaction, 'id'>) => {
    if (editingTransaction) {
        await StorageService.updateTransaction({ ...data, id: editingTransaction.id });
        if (user) await loadTransactions(user.id);
        setEditingTransaction(undefined);
        setShowAddModal(false);
    }
  };

  const handleDeleteTransaction = async (id: string) => {
    if (confirm('Are you sure you want to delete this transaction?')) {
      await StorageService.deleteTransaction(id);
      if (user) await loadTransactions(user.id);
    }
  };

  const openAddModal = () => {
    setEditingTransaction(undefined);
    setShowAddModal(true);
  };

  const openEditModal = (t: Transaction) => {
    setEditingTransaction(t);
    setShowAddModal(true);
  };

  const handleNaturalLanguageAdd = async () => {
    const input = prompt("Enter transaction (e.g., 'Spent $50 on groceries today')");
    if (!input || !user) return;

    // Quick visual feedback
    const originalText = document.title;
    document.title = "Processing AI...";

    try {
        const parsed = await GeminiService.parseNaturalLanguage(input);
        if (parsed && parsed.amount && parsed.description) {
            await StorageService.addTransaction({
                userId: user.id,
                amount: parsed.amount,
                description: parsed.description,
                category: parsed.category || 'Other',
                type: parsed.type || 'expense',
                date: parsed.date || new Date().toISOString().split('T')[0]
            });
            await loadTransactions(user.id);
            alert("Transaction added via AI!");
        } else {
            alert("Could not understand transaction.");
        }
    } catch (e) {
        console.error(e);
        alert("AI processing failed.");
    } finally {
        document.title = originalText;
    }
  };

  if (isLoading) {
    return <div className="min-h-screen flex items-center justify-center bg-gray-50 text-indigo-600">Loading SmartSpend...</div>;
  }

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <Layout user={user} currentPage={currentPage} onNavigate={setCurrentPage} onLogout={handleLogout}>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900 capitalize">
            {currentPage === 'reports' ? 'AI Insights' : currentPage}
        </h1>
        <div className="flex space-x-2">
            {GeminiService.isAvailable && currentPage === 'transactions' && (
                 <Button variant="secondary" onClick={handleNaturalLanguageAdd} className="hidden md:flex">
                    <Mic className="w-4 h-4 mr-2" />
                    Quick Add (AI)
                 </Button>
            )}
            <Button onClick={openAddModal}>
              <Plus className="w-4 h-4 mr-2" />
              Add Transaction
            </Button>
        </div>
      </div>

      {currentPage === 'dashboard' && <Dashboard transactions={transactions} />}

      {currentPage === 'transactions' && (
        <TransactionList 
          transactions={transactions} 
          onDelete={handleDeleteTransaction}
          onEdit={openEditModal}
        />
      )}

      {currentPage === 'reports' && <AIInsights transactions={transactions} />}

      {/* Modal Overlay */}
      {showAddModal && (
        <div className="fixed inset-0 bg-gray-500 bg-opacity-75 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-4 text-gray-900">
                {editingTransaction ? 'Edit Transaction' : 'New Transaction'}
            </h2>
            <TransactionForm 
              initialData={editingTransaction}
              userId={user.id}
              onSubmit={editingTransaction ? handleEditTransaction : handleAddTransaction}
              onCancel={() => setShowAddModal(false)}
            />
          </div>
        </div>
      )}
    </Layout>
  );
}

import React, { useState } from 'react';
import { Transaction } from '../types';
import { CATEGORIES } from '../constants';
import { Trash2, Edit2, ArrowUpCircle, ArrowDownCircle, X } from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

const TransactionList: React.FC<TransactionListProps> = ({ transactions, onDelete, onEdit }) => {
  const [filterType, setFilterType] = useState<'all' | 'income' | 'expense'>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const filteredTransactions = transactions.filter(t => {
    if (filterType !== 'all' && t.type !== filterType) return false;
    if (filterCategory !== 'all' && t.category !== filterCategory) return false;
    if (startDate && t.date < startDate) return false;
    if (endDate && t.date > endDate) return false;
    return true;
  });

  const clearFilters = () => {
    setFilterType('all');
    setFilterCategory('all');
    setStartDate('');
    setEndDate('');
  };

  const hasActiveFilters = filterType !== 'all' || filterCategory !== 'all' || startDate !== '' || endDate !== '';

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4">
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Type</label>
              <select
                value={filterType}
                onChange={(e) => setFilterType(e.target.value as any)}
                className="block w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500"
              >
                <option value="all">All Types</option>
                <option value="income">Income</option>
                <option value="expense">Expense</option>
              </select>
            </div>

            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Category</label>
              <select
                value={filterCategory}
                onChange={(e) => setFilterCategory(e.target.value)}
                className="block w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500"
              >
                <option value="all">All Categories</option>
                {CATEGORIES.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Start Date</label>
              <div className="relative">
                <input
                  type="date"
                  value={startDate}
                  onChange={(e) => setStartDate(e.target.value)}
                  className="block w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500"
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">End Date</label>
              <div className="relative">
                <input
                  type="date"
                  value={endDate}
                  onChange={(e) => setEndDate(e.target.value)}
                  className="block w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500"
                />
              </div>
            </div>
          </div>

          <div className="flex items-end">
            <button
              onClick={clearFilters}
              disabled={!hasActiveFilters}
              className={`px-4 py-2 text-sm font-medium rounded-md flex items-center transition-colors ${
                hasActiveFilters
                  ? 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                  : 'bg-gray-50 text-gray-400 cursor-not-allowed'
              }`}
            >
              <X className="w-4 h-4 mr-2" />
              Clear
            </button>
          </div>
        </div>
      </div>

      {/* Transaction Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredTransactions.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-10 text-center text-gray-500">
                    {transactions.length === 0 
                      ? "No transactions found. Add your first one!"
                      : "No transactions match your filters."}
                  </td>
                </tr>
              ) : (
                filteredTransactions.map((t) => (
                  <tr key={t.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Date(t.date).toLocaleDateString()}
