import React, { useState, useEffect, useRef } from 'react';
import { StorageService } from '../services/storage';
import { User } from '../types';
import Button from './Button';
import Input from './Input';
import { PieChart, Sparkles, TrendingUp, ShieldCheck, ArrowRight, CheckCircle2, DollarSign, Zap, Activity, CreditCard, Plus, ArrowUpRight, ArrowDownLeft } from 'lucide-react';

interface AuthProps {
  onLogin: (user: User) => void;
}

type AuthMode = 'landing' | 'login' | 'register';

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [mode, setMode] = useState<AuthMode>('landing');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Animation States
  const [heroText, setHeroText] = useState('');
  const fullHeroText = "SmartSpend";
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Typing effect
    let index = 0;
    const interval = setInterval(() => {
      setHeroText(fullHeroText.slice(0, index + 1));
      index++;
      if (index === fullHeroText.length) clearInterval(interval);
    }, 150);
    return () => clearInterval(interval);
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const { width, height, left, top } = containerRef.current.getBoundingClientRect();
    const x = (e.clientX - left) / width - 0.5;
    const y = (e.clientY - top) / height - 0.5;
    setMousePos({ x, y });
  };

  const handleMouseLeave = () => {
    setMousePos({ x: 0, y: 0 });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      let response;
      if (mode === 'login') {
        response = await StorageService.login(email, password);
      } else {
        if (!username) throw new Error("Username is required");
        response = await StorageService.register(username, email, password);
      }
      onLogin(response.user);
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const FeatureCard = ({ icon, title, desc, delay }: { icon: any, title: string, desc: string, delay: string }) => (
    <div className={`p-8 bg-white/60 backdrop-blur-md rounded-2xl shadow-sm border border-white/50 hover:shadow-xl hover:bg-white/90 transition-all duration-300 hover:-translate-y-2 group ${delay}`}>
      <div className="w-14 h-14 bg-gradient-to-br from-indigo-100 to-purple-100 rounded-2xl flex items-center justify-center text-indigo-600 mb-6 group-hover:scale-110 transition-transform duration-300 shadow-sm ring-1 ring-indigo-50">
        {icon}
      </div>
      <h3 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-indigo-600 transition-colors">{title}</h3>
      <p className="text-gray-600 leading-relaxed">{desc}</p>
    </div>
  );

  // --- Interactive Demo Widget Components ---
  const InteractiveDemoWidget = () => {
    const [balance, setBalance] = useState(2450.00);
    const [demoInput, setDemoInput] = useState('');
    const [transactions, setTransactions] = useState([
      { id: 1, label: 'Freelance', amount: 850, type: 'income', date: 'Just now' },
