                    </div>
                ))}
            </div>

            {/* Interactive Input */}
            <form onSubmit={handleDemoSubmit} className="mt-auto relative">
                <input 
                    type="text" 
                    value={demoInput}
                    onChange={(e) => setDemoInput(e.target.value)}
